import { Component, OnInit } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { CartService } from '../services/cart.service';
import { AuthService } from '../services/auth.service';
import { ToastService } from '../services/toast.service';
import { Product } from '../models/models';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent implements OnInit {
  products: Product[] = [];
  filteredProducts: Product[] = [];
  loading = true;
  error = '';
  selectedCategory = 'All';
  
  // For description expand/collapse
  expandedDescriptions: Set<number> = new Set();

  constructor(
    private http: HttpClient,
    private cartService: CartService,
    private authService: AuthService,
    private toastService: ToastService,
    private router: Router
  ) {}

  ngOnInit() {
    this.loadProducts();
  }

  loadProducts() {
    this.loading = true;
    this.http.get<Product[]>('http://localhost:3000/api/products')
      .subscribe({
        next: (data) => {
          this.products = data;
          this.filteredProducts = data;
          this.loading = false;
        },
        error: (error) => {
          this.error = 'Failed to load products';
          this.loading = false;
          this.toastService.showError('Failed to load products');
          console.error('Error loading products:', error);
        }
      });
  }

  filterByCategory(category: string) {
    this.selectedCategory = category;
    
    if (category === 'All') {
      this.filteredProducts = this.products;
    } else {
      this.filteredProducts = this.products.filter(p => p.category === category);
    }
  }

  toggleDescription(productId: number) {
    if (this.expandedDescriptions.has(productId)) {
      this.expandedDescriptions.delete(productId);
    } else {
      this.expandedDescriptions.add(productId);
    }
  }

  getDisplayDescription(product: Product): string {
    if (this.expandedDescriptions.has(product.id)) {
      return product.description;
    } else {
      return product.description.length > 60 ? 
        product.description.substring(0, 60) + '...' : 
        product.description;
    }
  }

  addToCart(product: Product) {
    if (!this.authService.isLoggedIn()) {
      this.toastService.showError('Please login to add items to cart');
      this.router.navigate(['/login']);
      return;
    }

    this.cartService.addToCart(product.id, 1).subscribe({
      next: () => {
        this.cartService.getCartCount();
        this.toastService.showSuccess(`${product.name} added to cart successfully!`);
      },
      error: (error) => {
        this.toastService.showError(error.error?.error || 'Failed to add to cart');
      }
    });
  }

  shopNow() {
    document.getElementById('products-section')?.scrollIntoView({ behavior: 'smooth' });
  }

  getCategoryIcon(category: string): string {
    const icons: {[key: string]: string} = {
      'Electronics': 'fas fa-laptop',
      'Fashion': 'fas fa-tshirt',
      'Home': 'fas fa-home',
      'Books': 'fas fa-book'
    };
    return icons[category] || 'fas fa-tag';
  }
}
